INSERT INTO cp_actividades (proyecto_id, requerido_por, consultor_asignado_id, descripcion_actividad, prioridad, fecha_hora_inicio, fecha_hora_fin, horas_trabajadas, estado, comentarios, situacion_pago) VALUES
((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Migración de tableros de control de MSTR a Power BI%' ORDER BY id DESC LIMIT 1), 'ricardo_martinez', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), 'Inducción y capacitación para migración de Strategy hacia power bi', 'media', '2025-10-30 09:00:00', '2025-10-30 18:00:00', 8.00, 'cerrado', 'capacitacionen Strategy y reunion con Ricardo y Freddy con referente a la migración. Se comienza a crear el bosquejo del tablero 1.', 'pendiente'),
((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Migración de tableros de control de MSTR a Power BI%' ORDER BY id DESC LIMIT 1), 'ricardo_martinez', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), 'Construcción de relaciones entre tablas que se trabajaran en el tablero. Creación de medidas DAX para los casos relacionados con las visualizaciones en tablas, medidor , tarjeta y grafica circular.', 'media', '2025-10-31 09:00:00', '2025-10-31 18:00:00', 8.00, 'cerrado', NULL, 'pendiente'),
((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Migración de tableros de control de MSTR a Power BI%' ORDER BY id DESC LIMIT 1), 'ricardo_martinez', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), '1-Creacion de formulas dax para optimizar recursos en cruce de tablas( treatas), se evitó usar power query. 2-Validacion de data con respecto a valores en microstrategy haciendo match con power bi. 3-Creacion de medidor de objetivo de nivel de servicio. 4-Informe de puntos pendientes.', 'media', '2025-11-03 09:00:00', '2025-11-03 18:00:00', 8.00, 'cerrado', NULL, 'pendiente'),
((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Migración de tableros de control de MSTR a Power BI%' ORDER BY id DESC LIMIT 1), 'ricardo_martinez', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), '1-Levantamiento de base de datos en STRATEGY para validar 2 tablas faltantes tabla 1: BOLETEOMM2 Y tabla 2: PPTOMM2 2-Revision de columnas faltantes en tablero de recetas medicas.', 'media', '2025-11-04 11:00:00', '2025-11-04 17:00:00', 6.00, 'cerrado', NULL, 'pendiente'),
((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Migración de tableros de control de MSTR a Power BI%' ORDER BY id DESC LIMIT 1), 'ricardo_martinez', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), 'Revisión de documentación de diseño y validación en ambos tableros para hacer match con los lineamientos generales.', 'media', '2025-11-05 09:00:00', '2025-11-05 18:00:00', 8.00, 'cerrado', NULL, 'pendiente'),
((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Modificaciones en los reportes de Power BI%' ORDER BY id DESC LIMIT 1), 'juan_pena', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), 'Se presento un primer informe con respecto a los tableros de power bi dentro de fabric relacionados a NEPAL tanto en el antiguo y nuevo. Existia diferencias notables entre ambos tomando como referencia el MGR.', 'media', '2025-11-10 05:00:00', '2025-11-10 13:00:00', 8.00, 'cerrado', NULL, 'pendiente'),
((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Modificaciones en los reportes de Power BI%' ORDER BY id DESC LIMIT 1), 'juan_pena', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), 'Se procedio a coordinar con Juan Peña tema de accesos a tableros antiguos y nuevos dentro de fabric Se procedio a revisar los filtros , se puso como fechas de rangos 01/04/25 al 31/08/25 y budget name : ARC26 Se procedio a validar el primer tablero MGR y la nueva metodologia para trabajar las validaciones por capas.', 'media', '2025-11-11 09:59:59', '2025-11-11 18:00:00', 8.00, 'cerrado', NULL, 'pendiente'),
((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Modificaciones en los reportes de Power BI%' ORDER BY id DESC LIMIT 1), 'juan_pena', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), 'Se hace la revision por capas las medidas dax tomando como referencia principal el modelo semantico unico que asocia a todos los informes. se ha hecho las primeras modificaciones en tablero de power bi de la pestaña dashboard.', 'media', '2025-11-12 09:00:00', '2025-11-12 18:00:00', 8.00, 'cerrado', NULL, 'pendiente'),
