((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Modificaciones en los reportes de Power BI%' ORDER BY id DESC LIMIT 1), 'juan_pena', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), 'informe preliminar de las demas pestañas de MGR y modificaciones de las capa de modelo e informe.', 'media', '2025-11-14 09:00:00', '2025-11-14 18:00:00', 8.00, 'cerrado', NULL, 'pendiente'),
