((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Modificaciones en los reportes de Power BI%' ORDER BY id DESC LIMIT 1), 'juan_pena', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), 'Ordenamiento de Category de acuerdo a orden enviado por el cliente a reporte MGR. Se ha analizado la tabla asociado en BI y no se ha creado otras tablas o columnas sino se ha reutilizado los que se tenia para hacer el ordenamiento solicitado.', 'media', '2026-03-20 12:30:00', '2026-03-20 15:00:00', 2.00, 'cerrado', NULL, 'pendiente'),
