((SELECT id FROM cp_proyectos WHERE proyecto LIKE '%Modificaciones en los reportes de Power BI%' ORDER BY id DESC LIMIT 1), 'juan_pena', (SELECT id FROM empleados WHERE apellidos LIKE '%Llanca%' AND (nombres LIKE '%Oscar%' OR nombres LIKE '%Óscar%') LIMIT 1), '1- Análisis del reporte Budget Holder Report para validar la lógica y ver porque existe valores que comienzan con valor diferente de 7 2- Se comienza con el análisis de "Budget Holder Summary" y el reporte cost coverage graph.', 'media', '2026-03-25 12:52:00', '2026-03-25 18:59:59', 5.00, 'cerrado', NULL, 'pendiente'),
